#pr-preview-root {
  margin: 0;
  background: #0a0a0a;
  color: #fafafa;
  font-family: Inter, system-ui, sans-serif;
  -webkit-font-smoothing: antialiased;
  color-scheme: dark;
}
#pr-preview-root *, #pr-preview-root *::before, #pr-preview-root *::after { box-sizing: border-box; }
#pr-preview-root[data-demo-hide-rest="true"] [data-demo-region="main-content"] {
  opacity: 0.18;
  filter: blur(4px);
  transform: scale(0.98);
  transition: opacity 0.35s ease, filter 0.35s ease, transform 0.35s ease;
  pointer-events: none;
}
#pr-preview-root[data-demo-focus-ref] [data-demo-ref] {
  transition: transform 0.25s ease, opacity 0.25s ease, box-shadow 0.25s ease;
}
